import React from 'react'

const Additems = ({newItem,setNewItem,handleSumbit}) => {
  return (
    <form className='addForm' onSumbit={handleSumbit}>
        <label htmlFor="additem">Add Item</label>
        <input autofocus id='addItem' type="text" placeholder='Add Ur Wish Activities...' required value={newItem} onChange={(e)=>setNewItem(e.target)} />
        <button type='sumbit' aria-label='Add Items'>+</button>
    </form>
  )
}

export default Additems
